return $input.all().map(item => {
  const ev = item.json;

  // Datum DD.MM.YYYY → ISO
  let isoDatum = '';
  const datumRaw = ev['EventDatum'] || '';
  const match = datumRaw.match(/(\d{2})\.(\d{2})\.(\d{4})/);
  if (match) isoDatum = `${match[3]}-${match[2]}-${match[1]}`;

  // Event-Bild URL aus NocoDB Attachment extrahieren
  let bild = '';
  try {
    const att = ev['Event-Bild'];
    const parsed = typeof att === 'string' ? JSON.parse(att) : att;
    if (Array.isArray(parsed) && parsed.length > 0) {
      const path = parsed[0].signedPath || parsed[0].path || parsed[0].url || '';
      bild = path.startsWith('http') ? path : 'https://nocodb.f3-events.de/' + path;
    }
  } catch(e) {}

  return {
    json: {
      name:            ev['EventName'] || '',
      datum:           datumRaw,
      isoDatum,
      status:          ev['Status'] || 'aktiv',
      beschreibung:    ev['Event-Beschreibung'] || '',
      link:            ev['EventLink'] || '',
      zusatz:          ev['Wochentag'] || '',
      bild,
      angemeldet:      ev['Angemeldet'] || 0,
      nichtBestaetigt: ev['NichtBestaetigt'] || 0,
      vorgemerkt:      ev['Vorgemerkt'] || 0,
      aufrufe:         ev['Aufrufe'] || 0,
      maenner:         ev['Maenner'] || 0,
      frauen:          ev['Frauen'] || 0,
      paare:           ev['Paare'] || 0
    }
  };
});
